export const getGetProjectStatsUrl = (id: number) => {
  return `/api/projects/${id}/stats`;
};

export const getProjectStats = async (
  id: number,
  options?: RequestInit,
): Promise<ProjectStats> => {
  return customFetch<ProjectStats>(getGetProjectStatsUrl(id), {
    ...options,
    method: "GET",
  });
};

export const getGetProjectStatsQueryKey = (id: number) => {
  return [`/api/projects/${id}/stats`] as const;
};

export const getGetProjectStatsQueryOptions = <
  TData = Awaited<ReturnType<typeof getProjectStats>>,
  TError = ErrorType<unknown>,
>(
  id: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getProjectStats>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetProjectStatsQueryKey(id);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getProjectStats>>> = ({
    signal,
  }) => getProjectStats(id, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!id,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getProjectStats>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetProjectStatsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getProjectStats>>
>;
export type GetProjectStatsQueryError = ErrorType<unknown>;

/**
 * @summary Get task stats for a project
 */

export function useGetProjectStats<
  TData = Awaited<ReturnType<typeof getProjectStats>>,
  TError = ErrorType<unknown>,
>(
  id: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getProjectStats>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetProjectStatsQueryOptions(id, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

